SELECT status, description
FROM conservation_status
WHERE status != 'endangered';

SELECT habitat_id
FROM habitats
WHERE habitat_type = 'Marine';

SELECT evaluation, comments
FROM expert_assessments
WHERE assessment_date >= date('now', '-30 days');

SELECT COUNT(*) 
FROM groups 
WHERE is_active = 1;

SELECT assessment_id, species_id, habitat_id, assessment_date, population_estimate, assessment_method_id, confidence_level, created_date, modified_date
FROM assessments
WHERE species_id = 1;

SELECT title
FROM literature_references
WHERE authors LIKE '%Alice Johnson%' AND authors LIKE '%Bob Williams%';

SELECT COUNT(*)
FROM habitats
WHERE habitat_type = 'Freshwater' AND is_protected = 1;

SELECT taxonomic_id 
FROM taxonomic_classification 
WHERE genus = 'Crassula' AND species = 'floridana';

SELECT species
FROM taxonomic_classification
WHERE taxonomic_id = 1;
